const groqResponse = $input.first().json;
const topicData = $('Code — Parse Topic').first().json;

const rawText = groqResponse?.choices?.[0]?.message?.content ?? '{}';
const cleaned = rawText.replace(/```json\s*/gi,'').replace(/```\s*/gi,'').trim();

let content;
try { content = JSON.parse(cleaned); }
catch(e) {
  content = {
    linkedin_post: 'Content generation failed. Please retry.',
    blog_title: topicData.topic,
    blog_content: 'Content generation failed. Please retry.',
    hashtags: '#PersonalFinance #Investing #Money #Finance #WealthBuilding',
    linkedin_hook: topicData.topic,
    seo_description: topicData.topic
  };
}

// Clean up text for safe use in API calls
const cleanText = (str) => (str ?? '').replace(/\n/g, '\n').trim();

return [{
  json: {
    // Topic data
    topic:             topicData.topic,
    angle:             topicData.angle,
    content_type:      topicData.content_type,
    target_emotion:    topicData.target_emotion,
    date:              topicData.date,

    // Generated content
    linkedin_post:     cleanText(content.linkedin_post),
    linkedin_hook:     cleanText(content.linkedin_hook),
    blog_title:        cleanText(content.blog_title),
    blog_content:      cleanText(content.blog_content),
    hashtags:          cleanText(content.hashtags),
    seo_description:   cleanText(content.seo_description),

    // Full LinkedIn post with hashtags
    linkedin_full:     cleanText(content.linkedin_post) + '\n\n' + cleanText(content.hashtags)
  }
}];
